let cachedFileId = null;
const IMG_B64 = '';

function api(method, data) {
  return new Promise((resolve, reject) => {
    const body = JSON.stringify(data);
    const req = https.request({
      hostname: 'api.telegram.org',
      path: `/bot${TOKEN}/${method}`,
      method: 'POST',
      headers: { 'Content-Type': 'application/json', 'Content-Length': Buffer.byteLength(body) }
    }, res => {
      let d = '';
      res.on('data', c => d += c);
      res.on('end', () => { try { resolve(JSON.parse(d)); } catch(e) { resolve({}); } });
    });
    req.on('error', reject);
    req.write(body);
    req.end();
  });
}

function apiMultipart(method, fields, fileBuffer, filename) {
  return new Promise((resolve, reject) => {
    const boundary = '----FormBoundary' + Math.random().toString(36);
    let body = Buffer.alloc(0);
    for (const [key, val] of Object.entries(fields)) {
      const part = `--${boundary}\r\nContent-Disposition: form-data; name="${key}"\r\n\r\n${typeof val === 'object' ? JSON.stringify(val) : val}\r\n`;
      body = Buffer.concat([body, Buffer.from(part)]);
    }
    const fileHeader = `--${boundary}\r\nContent-Disposition: form-data; name="photo"; filename="${filename}"\r\nContent-Type: image/png\r\n\r\n`;
    body = Buffer.concat([body, Buffer.from(fileHeader), fileBuffer, Buffer.from(`\r\n--${boundary}--\r\n`)]);
    const req = https.request({
      hostname: 'api.telegram.org',
      path: `/bot${TOKEN}/${method}`,
      method: 'POST',
      headers: { 'Content-Type': `multipart/form-data; boundary=${boundary}`, 'Content-Length': body.length }
    }, res => {
      let d = '';
      res.on('data', c => d += c);
      res.on('end', () => { try { resolve(JSON.parse(d)); } catch(e) { resolve({}); } });
    });
    req.on('error', reject);
    req.write(body);
    req.end();
  });
}

async function sendWithPhoto(chatId, caption) {
  const imgBuffer = Buffer.from(IMG_B64, 'base64');
  if (cachedFileId) {
    return await api('sendPhoto', {
      chat_id: chatId, photo: cachedFileId,
      caption, parse_mode: 'Markdown', reply_markup: KEYBOARD
    });
  }
  const res = await apiMultipart('sendPhoto', {
    chat_id: chatId, caption,
    parse_mode: 'Markdown', reply_markup: JSON.stringify(KEYBOARD)
  }, imgBuffer, 'masterterpz.png');
  if (res.ok && res.result?.photo) {
    cachedFileId = res.result.photo[res.result.photo.length - 1].file_id;
    console.log('Image uploaded and cached');
  }
  return res;
}

let offset = 0;

async function poll() {
  try {
    const res = await api('getUpdates', { offset, timeout: 30, limit: 100, allowed_updates: ['message'] });
    if (res.ok && res.result?.length) {
      for (const update of res.result) {
        offset = update.update_id + 1;
        const msg = update.message;
        if (!msg?.text) continue;
        const chatId = msg.chat.id;
        const name = msg.from?.first_name || 'there';
        console.log(`Message from ${name}: ${msg.text}`);
        if (msg.text.startsWith('/start') || msg.text.startsWith('/menu')) {
          await sendWithPhoto(chatId, WELCOME);
        } else {
          await sendWithPhoto(chatId, `Hey ${name}! 👋 Use the menu below 👇`);
        }
      }
    }
  } catch(e) { console.error('Poll error:', e.message); }
  setTimeout(poll, 1500);
}

async function start() {
  try {
    await api('deleteWebhook', { drop_pending_updates: true });
    const me = await api('getMe', {});
    console.log(`Bot running: @${me.result?.username}`);
    await api('setMyCommands', { commands: [
      { command: 'start', description: '🧪 Open MasterTerpz menu' },
      { command: 'menu', description: '📋 Show all options' }
    ]});
    await api('setChatMenuButton', { menu_button: {
      type: 'web_app', text: '🏪 Showroom',
      web_app: { url: 'https://premiumhoodies.io/mini-app' }
    }});
    console.log('Ready — polling...');
    poll();
  } catch(e) {
    console.error('Startup error:', e.message);
    setTimeout(start, 5000);
  }
}

start();
